import { useSelector, useDispatch } from "react-redux";
import { axiosExampleTasks, selectLoading } from "../tasksSlice";
import { Button } from "../Buttons/styled";

const AxiosExampleTasksButton = () => {
    const dispatch = useDispatch();
    const loading = useSelector(selectLoading);

    return (
        <Button disabled={loading} onClick={() => dispatch(axiosExampleTasks())}>
            {loading ? "Loading..." : "Load example tasks"}
        </Button>
    );
};

export default AxiosExampleTasksButton;
