import { Link } from "react-router-dom";
import styled, { css } from "styled-components";

interface TaskActions {
    $hidden?: boolean;
    $done?: boolean;
    $toggleDone?: boolean;
    $remove?: boolean;
}

export const List = styled.ul`
    list-style: none;
    padding: 0;
    margin: 0;
`;

export const Item = styled.li<TaskActions>`
    display: grid;
    grid-template-columns: auto 1fr auto;
    align-items: center;
    padding: 8px 10px;
    border-radius: 8px;
    border-bottom: 1px solid ${({ theme }) => theme.color.taskBorder};
    transition: background-color 0.15s;

    &:hover {
        background-color: ${({ theme }) => theme.color.taskHoverBg};
    }

    ${({ $hidden }) => $hidden && css`display: none;`}
`;

export const Content = styled.span<TaskActions>`
    color: ${({ $done, theme }) => $done ? theme.color.taskDoneColor : theme.color.textPrimary};
    ${({ $done }) => $done && css`text-decoration: line-through;`}
    transition: color 0.2s;
`;

export const Button = styled.button<TaskActions>`
    border: none;
    width: 32px;
    height: 32px;
    padding: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 6px;
    font-size: 15px;
    transition: background-color 0.2s;

    ${({ $toggleDone, theme }) => $toggleDone && css`
        background-color: ${theme.color.primary};
        color: ${theme.color.primaryText};
        &:hover { background-color: ${theme.color.primaryHover}; }
    `}

    ${({ $remove, theme }) => $remove && css`
        background-color: transparent;
        color: ${theme.color.textMuted};
        &:hover { background-color: #fee2e2; color: #dc2626; }
    `}
`;

export const StyledLink = styled(Link)`
    color: ${({ theme }) => theme.color.textPrimary};
    text-decoration: none;
    padding: 0 12px;
    line-height: 1.6;
    transition: color 0.2s;

    &:hover {
        color: ${({ theme }) => theme.color.primary};
    }
`;
